async (params, browser) => {
  // Open video page
  await browser.open(`${params.video_url}`)

  // Wait for video to load
  await browser.waitForSelector('[data-e2e="like-count"], [data-e2e="browse-like-count"]', 15000)

  // Let video and comments load
  await browser.wait(3000)

  // Scroll to comments section
  await browser.scroll({ direction: 'down', amount: 800 })

  // Wait for comments to render
  await browser.wait(2500)

  // Scroll to load more comments
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll for additional comments
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract comments
  const comments_data = await browser.evaluate(`const comments = []; const commentEls = document.querySelectorAll('[data-e2e="comment-item"], .comment-container, div[class*="DivCommentItemContainer"], div[class*="DivCommentContentContainer"]'); for (let i = 0; i < Math.min(commentEls.length, 20); i++) { const el = commentEls[i]; const authorEl = el.querySelector('[data-e2e="comment-username-1"], a[data-e2e="comment-avatar-1"] + div a, span[data-e2e="comment-username-1"], a.comment-user'); const contentEl = el.querySelector('[data-e2e="comment-level-1"] p, p[data-e2e="comment-level-1"], .comment-text, span[class*="SpanCommentText"]'); const likesEl = el.querySelector('[data-e2e="comment-like-count"], span.like-count, span[class*="SpanCount"]'); const timeEl = el.querySelector('[data-e2e="comment-time-1"], span.comment-time, span[class*="SpanCreatedTime"]'); const isCreator = !!el.querySelector('[data-e2e="comment-creator-badge"], .creator-badge, div[class*="DivCreatorTag"]'); const isPinned = !!el.querySelector('[data-e2e="comment-pinned"], .pinned-badge, div[class*="DivPinnedLabel"]'); const isLikedByCreator = !!el.querySelector('[data-e2e="comment-creator-like"], .creator-liked'); comments.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', content: contentEl ? contentEl.textContent.trim().substring(0, 500) : '', likes: likesEl ? likesEl.textContent.trim() : '0', time: timeEl ? timeEl.textContent.trim() : '', is_creator: isCreator, is_pinned: isPinned, liked_by_creator: isLikedByCreator }); } const totalCommentsEl = document.querySelector('[data-e2e="comment-count"], [data-e2e="browse-comment-count"]'); return { total_comment_count: totalCommentsEl ? totalCommentsEl.textContent.trim() : '', scraped_count: comments.length, comments: comments }`)

  return comments_data
}
